    <div class="container">
        <header>
            <h1>🏥 Cedars-Sinai Urgent Care</h1>
            <h2>Beverly Hills Health Analysis Report</h2>
            <p class="subtitle">Population Estimation & Disease Prevalence Projection</p>
            <p style="margin-top: 15px; color: #666;">Analysis Date: March 26, 2026</p>
        </header>

        <div class="grid">
            <!-- Location & Map -->
            <div class="card">
                <h3>📍 Geographic Analysis</h3>
                <div class="map-container">
                    <div class="map-visual">
                        <div class="circle radius-circle"></div>
                        <div class="circle location-marker" title="Cedars-Sinai Urgent Care"></div>
                        <div class="circle area-marker" style="top: 20%; left: 60%;" title="Beverly Hills"></div>
                        <div class="circle area-marker" style="top: 70%; left: 30%;" title="Century City"></div>
                        <div class="circle area-marker" style="top: 30%; left: 20%;" title="Westwood"></div>
                    </div>
                    <p style="color: #888; margin-top: 15px;">
                        <span style="color: #00ff88;">●</span> Cedars-Sinai Urgent Care<br>
                        <span style="color: #E94F37;">●</span> Surrounding Areas
                    </p>
                </div>
            </div>

            <!-- Key Statistics -->
            <div class="card">
                <h3>📊 Service Area Statistics</h3>
                <div class="stat-box">
                    <div class="stat-number">82,500</div>
                    <div class="stat-label">Estimated Population (2-mile radius)</div>
                </div>
                <div class="info-grid">
                    <div class="info-item">
                        <strong>📐 Area Size</strong>
                        12.57 sq miles
                    </div>
                    <div class="info-item">
                        <strong>🏠 Density</strong>
                        ~6,560/sq mile
                    </div>
                    <div class="info-item">
                        <strong>📍 Address</strong>
                        8500 Wilshire Blvd
                    </div>
                    <div class="info-item">
                        <strong>🏙️ City</strong>
                        Beverly Hills, CA
                    </div>
                </div>
            </div>

            <!-- Population by Area -->
            <div class="card">
                <h3>👥 Population Distribution</h3>
                <div class="chart-container">
                    <canvas id="populationChart"></canvas>
                </div>
            </div>

            <!-- Age Distribution -->
            <div class="card">
                <h3>👴 Age Distribution</h3>
                <div class="chart-container">
                    <canvas id="ageChart"></canvas>
                </div>
            </div>

            <!-- Disease Prevalence -->
            <div class="card full-width">
                <h3>🏨 Disease Prevalence Estimates</h3>
                <p style="color: #888; margin-bottom: 20px;">
                    Based on LA County Department of Public Health epidemiologic data, adjusted for local demographics
                </p>
                <table>
                    <thead>
                        <tr>
                            <th>Disease/Condition</th>
                            <th>Prevalence Rate</th>
                            <th>Estimated Cases</th>
                            <th>Percentage</th>
                        </tr>
                    </thead>
                    <tbody id="diseaseTable">
                    </tbody>
                </table>
            </div>

            <!-- Top Diseases Chart -->
            <div class="card">
                <h3>📈 Top Diseases by Prevalence</h3>
                <div class="chart-container">
                    <canvas id="topDiseasesChart"></canvas>
                </div>
            </div>

            <!-- Comparison Chart -->
            <div class="card">
                <h3>📉 vs. California State Average</h3>
                <div class="chart-container">
                    <canvas id="comparisonChart"></canvas>
                </div>
            </div>

            <!-- Summary -->
            <div class="card full-width summary-card">
                <h3>📋 Executive Summary</h3>
                <div class="info-grid">
                    <div class="info-item">
                        <strong>Population Estimate</strong>
                        <span class="highlight">82,500</span> permanent residents within 2-mile radius
                    </div>
                    <div class="info-item">
                        <strong>Primary Health Concerns</strong>
                        High cholesterol, hypertension, and obesity lead in estimated prevalence
                    </div>
                    <div class="info-item">
                        <strong>Demographic Factors</strong>
                        Higher socioeconomic status, older median age (45+), lower obesity rates than CA average
                    </div>
                    <div class="info-item">
                        <strong>Data Sources</strong>
                        CDC, CA DPH, US Census Bureau, LA County Health Survey
                    </div>
                </div>
                <div class="disclaimer">
                    <strong>⚠️ Disclaimer:</strong> These estimates are based on epidemiologic statistics and census data. 
                    Actual disease prevalence varies based on individual risk factors, screening rates, and diagnostic practices. 
                    This analysis is for informational purposes only and is not a substitute for professional medical advice.
                </div>
            </div>
        </div>

        <footer>
            <p>Report generated for educational/informational purposes | Data: US Census, LA County DPH, CDC</p>
        </footer>
    </div>

    <script>
        // Population data
        const populationData = {
            'Beverly Hills': 19500,
            'Century City': 9600,
            'Westwood': 9000,
            'Mid-Wilshire': 13750,
            'Other Areas': 30650
        };

        // Age distribution
        const ageData = {
            '0-17': 0.15,
            '18-34': 0.18,
            '35-49': 0.22,
            '50-64': 0.24,
            '65+': 0.21
        };

        // Disease prevalence (per 100,000)
        const totalPopulation = 82500;
        const diseaseData = [
            { name: 'High Cholesterol', rate: 2800, cases: Math.round(totalPopulation * 0.028) },
            { name: 'Hypertension', rate: 2450, cases: Math.round(totalPopulation * 0.0245) },
            { name: 'Obesity (Adult)', rate: 2400, cases: Math.round(totalPopulation * 0.024) },
            { name: 'Arthritis', rate: 2200, cases: Math.round(totalPopulation * 0.022) },
            { name: 'Anxiety Disorders', rate: 2100, cases: Math.round(totalPopulation * 0.021) },
            { name: 'Depression', rate: 1850, cases: Math.round(totalPopulation * 0.0185) },
            { name: 'Heart Disease', rate: 1680, cases: Math.round(totalPopulation * 0.0168) },
            { name: 'Diabetes (Adult)', rate: 980, cases: Math.round(totalPopulation * 0.0098) },
            { name: 'Asthma', rate: 980, cases: Math.round(totalPopulation * 0.0098) },
            { name: 'COPD', rate: 560, cases: Math.round(totalPopulation * 0.0056) },
            { name: 'Chronic Kidney Disease', rate: 380, cases: Math.round(totalPopulation * 0.0038) },
            { name: 'Cancer (All Types)', rate: 420, cases: Math.round(totalPopulation * 0.0042) },
            { name: 'Stroke', rate: 280, cases: Math.round(totalPopulation * 0.0028) }
        ];

        // Sort by cases
        diseaseData.sort((a, b) => b.cases - a.cases);

        // Populate table
        const tableBody = document.getElementById('diseaseTable');
        diseaseData.forEach(disease => {
            const row = document.createElement('tr');
            row.innerHTML = `
                <td>${disease.name}</td>
                <td>${disease.rate.toLocaleString()}</td>
                <td><strong>${disease.cases.toLocaleString()}</strong></td>
                <td>${(disease.rate / 100).toFixed(1)}%</td>
            `;
            tableBody.appendChild(row);
        });

        // Population Chart
        new Chart(document.getElementById('populationChart'), {
            type: 'doughnut',
            data: {
                labels: Object.keys(populationData),
                datasets: [{
                    data: Object.values(populationData),
                    backgroundColor: [
                        '#00d9ff',
                        '#00ff88',
                        '#ff6b6b',
                        '#ffd93d',
                        '#6c5ce7'
                    ],
                    borderWidth: 0
                }]
            },
            options: {
                responsive: true,
                maintainAspectRatio: false,
                plugins: {
                    legend: {
                        position: 'right',
                        labels: { color: '#fff' }
                    }
                }
            }
        });

        // Age Chart
        new Chart(document.getElementById('ageChart'), {
            type: 'bar',
            data: {
                labels: Object.keys(ageData),
                datasets: [{
                    label: 'Population %',
                    data: Object.values(ageData).map(v => v * 100),
                    backgroundColor: ['#ff6b6b', '#4ecdc4', '#45b7d1', '#96ceb4', '#ffeaa7'],
                    borderRadius: 8
